1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PRICE_BY_TYPE: Record<string, number> = {
5	  potion: 40,
6	  amulet: 60,
7	  staff: 80,
8	  sword: 100,
9	  rune: 25,
10	};
11	
12	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string }[] }): number {
13	  const basePrice = input.items.reduce((sum, item) => sum + BASE_PRICE_BY_TYPE[item.type], 0);
14	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
15	  const premium = basePrice + firstInsuranceSurcharge + PROCESSING_FEE;
16	  return Math.ceil(premium);
17	}
